const body = $input.first().json.body || $input.first().json;
const tenantId = body.tenantId;
const fromAddress = body.fromAddress || '';
const toAddress = body.toAddress || '';
const subject = body.subject || '';
const bodyText = body.bodyText || '';
const bodyHtml = body.bodyHtml || '';
const emailId = body.emailId || null;

if (!tenantId || !fromAddress) {
  return [{ json: { valid: false, error: 'tenantId et fromAddress requis' } }];
}

return [{ json: {
  tenantId,
  emailId,
  fromAddress,
  toAddress,
  subject,
  bodyText,
  bodyHtml,
  bodyPreview: bodyText.substring(0, 500),
  valid: true
} }];

const email = $('02. Valider').first().json;
const classifyResult = $input.first().json;
const classification = classifyResult.data || classifyResult;
const category = classification.category || 'general';
const priority = classification.priority || 'normal';
const intent = classification.intent || 'unknown';
const confidenceThreshold = 0.85;

// Décider de l'action
let replyAction = 'queue_human'; // par défaut
if (classification.autoReplyEligible === true && (classification.confidence || 0) >= confidenceThreshold) {
  replyAction = 'sent_auto';
}

return [{ json: {
  ...email,
  classification: { category, priority, intent, confidence: classification.confidence || 0 },
  replyAction,
  needsReply: replyAction !== 'none'
} }];

const email = $('04. Décider action').first().json;
const replyResult = $input.first().json;
const replyData = replyResult.data || replyResult;

return [{ json: {
  tenantId: email.tenantId,
  emailId: email.emailId,
  fromAddress: email.fromAddress,
  toAddress: email.toAddress,
  subject: email.subject,
  bodyPreview: email.bodyPreview,
  classification: email.classification,
  action: email.replyAction === 'sent_auto' ? 'auto_replied' : 'classified',
  replySubject: replyData.subject || ('Re: ' + email.subject),
  replyBody: replyData.text || '',
  replyHtml: replyData.html || '',
  replyConfidence: replyData.confidence || email.classification.confidence || 0,
  replyAction: email.replyAction,
  tokensUsed: replyData.tokensUsed || 0
} }];
